/**
 * Menu Module Definition
 *
 * Feature module for digital menu management in E-Menum.
 * Provides menu, category, product, variant, and modifier management.
 *
 * This is a FEATURE module - it can be enabled/disabled per organization.
 *
 * @module modules/menu/menu.module
 *
 * @example
 * ```typescript
 * import { MenuModule } from '@/modules/menu/menu.module';
 *
 * // Module is automatically discovered and loaded by ModuleLoader
 * // Access module instance via DI container
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
import type { ModuleInstance } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

import { MenuController, CategoryController, ProductController } from '@/modules/menu/menu.controller';
import { MenuService } from '@/modules/menu/menu.service';
import { CategoryService } from '@/modules/menu/category.service';
import { ProductService } from '@/modules/menu/product.service';
import { MenuRepository } from '@/modules/menu/menu.repository';
import { CategoryRepository } from '@/modules/menu/category.repository';
import { ProductRepository } from '@/modules/menu/product.repository';
import { menuRoutes, categoryRoutes, productRoutes } from '@/modules/menu/menu.routes';
import type { MenuModuleSettings } from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Module Types
// -----------------------------------------------------------------------------

/**
 * Menu module context for lifecycle hooks
 */
export interface MenuModuleContext {
  /** Event service for pub/sub */
  events: EventService;
  /** Module settings */
  settings: MenuModuleSettings;
  /** Logger function */
  log: (message: string) => void;
}

/**
 * Menu module hook definitions
 */
export interface MenuModuleHooks {
  /** Called before menu creation */
  beforeMenuCreate?: (data: { name: string; organizationId: string }) => Promise<void>;
  /** Called after menu creation */
  afterMenuCreate?: (data: { menuId: string; organizationId: string }) => Promise<void>;
  /** Called before menu publishing */
  beforeMenuPublish?: (data: { menuId: string; organizationId: string }) => Promise<void>;
  /** Called after menu publishing */
  afterMenuPublish?: (data: { menuId: string; organizationId: string; publishedAt: Date }) => Promise<void>;
  /** Called before product creation */
  beforeProductCreate?: (data: { categoryId: string; name: string; organizationId: string }) => Promise<void>;
  /** Called after product creation */
  afterProductCreate?: (data: { productId: string; categoryId: string; organizationId: string }) => Promise<void>;
  /** Called before product update */
  beforeProductUpdate?: (data: { productId: string; organizationId: string }) => Promise<void>;
  /** Called after product update */
  afterProductUpdate?: (data: { productId: string; organizationId: string }) => Promise<void>;
  /** Called before category creation */
  beforeCategoryCreate?: (data: { menuId: string; name: string; organizationId: string }) => Promise<void>;
  /** Called after category creation */
  afterCategoryCreate?: (data: { categoryId: string; menuId: string; organizationId: string }) => Promise<void>;
}

// -----------------------------------------------------------------------------
// Menu Module Class
// -----------------------------------------------------------------------------

/**
 * Menu Module
 *
 * Feature module providing digital menu management for E-Menum.
 * Handles menu, category, product, variant, and modifier operations.
 *
 * Features:
 * - Menu CRUD with publishing workflow
 * - Category hierarchy with drag-and-drop reordering
 * - Product management with variants and modifiers
 * - Allergen and nutrition information
 * - Theme customization
 * - QR code generation
 *
 * @example
 * ```typescript
 * // Module is automatically loaded by ModuleLoader
 * // Use MenuService for business logic
 * const menuService = container.resolve('MenuService');
 * await menuService.create(orgId, { name: 'Lunch Menu' });
 * ```
 */
@injectable()
export class MenuModule implements ModuleInstance {
  // ---------------------------------------------------------------------------
  // Static Properties
  // ---------------------------------------------------------------------------

  /** Module ID */
  static readonly id = 'menu';

  /** Module name */
  static readonly name = 'Menu Module';

  /** Module version */
  static readonly version = '1.0.0';

  /** Is core module (cannot be disabled) */
  static readonly isCore = false;

  /** Module type */
  static readonly type = 'feature';

  /** Module routes configuration */
  static readonly routes = {
    menus: menuRoutes,
    categories: categoryRoutes,
    products: productRoutes,
  };

  /** Providers (services) to register */
  static readonly providers = [
    MenuService,
    CategoryService,
    ProductService,
    MenuRepository,
    CategoryRepository,
    ProductRepository,
  ];

  /** Controllers to register */
  static readonly controllers = [
    MenuController,
    CategoryController,
    ProductController,
  ];

  /** Module dependencies */
  static readonly dependencies = {
    required: ['auth', 'organization', 'media'],
    optional: ['ai'],
  };

  // ---------------------------------------------------------------------------
  // Instance Properties
  // ---------------------------------------------------------------------------

  /** Module hooks registry */
  private hooks: MenuModuleHooks = {};

  /** Module initialized flag */
  private initialized = false;

  constructor(
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // ModuleInstance Lifecycle Hooks
  // ---------------------------------------------------------------------------

  /**
   * Called when module is loaded.
   * Registers services with DI container.
   */
  async onLoad(): Promise<void> {
    this.log('Loading menu module...');

    // Register repositories
    if (!appContainer.isRegistered('MenuRepository')) {
      registerSingleton('MenuRepository', MenuRepository);
    }
    if (!appContainer.isRegistered('CategoryRepository')) {
      registerSingleton('CategoryRepository', CategoryRepository);
    }
    if (!appContainer.isRegistered('ProductRepository')) {
      registerSingleton('ProductRepository', ProductRepository);
    }

    // Register services
    if (!appContainer.isRegistered('MenuService')) {
      registerSingleton('MenuService', MenuService);
    }
    if (!appContainer.isRegistered('CategoryService')) {
      registerSingleton('CategoryService', CategoryService);
    }
    if (!appContainer.isRegistered('ProductService')) {
      registerSingleton('ProductService', ProductService);
    }

    this.log('Menu module loaded');
  }

  /**
   * Called when module is enabled/activated.
   * Sets up event listeners and registers routes.
   */
  async onEnable(): Promise<void> {
    if (this.initialized) {
      this.log('Menu module already initialized');
      return;
    }

    this.log('Enabling menu module...');

    // Subscribe to relevant events
    this.setupEventListeners();

    this.initialized = true;
    this.log('Menu module enabled');

    // Emit module activated event
    await this.eventService.emitCustom('module.activated', {
      moduleId: MenuModule.id,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Called when module is disabled/deactivated.
   * Cleans up event listeners.
   */
  async onDisable(): Promise<void> {
    this.log('Disabling menu module...');

    // Feature modules can be disabled
    // Clean up would happen here if needed

    this.initialized = false;
    this.log('Menu module disabled');
  }

  /**
   * Called when module is unloaded.
   * Cleans up resources.
   */
  async onUnload(): Promise<void> {
    this.log('Unloading menu module...');

    // Clear hooks
    this.hooks = {};

    this.log('Menu module unloaded');
  }

  // ---------------------------------------------------------------------------
  // ModuleInstance Interface Methods
  // ---------------------------------------------------------------------------

  /**
   * Returns module routes for registration with Express.
   *
   * @returns Route configuration array
   */
  getRoutes(): unknown[] {
    return [MenuModule.routes];
  }

  /**
   * Returns module controllers for registration with routing-controllers.
   *
   * @returns Controller class array
   */
  getControllers(): unknown[] {
    return MenuModule.controllers;
  }

  // ---------------------------------------------------------------------------
  // Hook System
  // ---------------------------------------------------------------------------

  /**
   * Gets current module hooks.
   *
   * @returns Module hooks object
   */
  getHooks(): MenuModuleHooks {
    return { ...this.hooks };
  }

  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Hook handler function
   *
   * @example
   * ```typescript
   * menuModule.registerHook('afterMenuPublish', async (data) => {
   *   console.log('Menu published:', data.menuId);
   * });
   * ```
   */
  registerHook<K extends keyof MenuModuleHooks>(
    hookName: K,
    handler: MenuModuleHooks[K]
  ): void {
    this.hooks[hookName] = handler;
    this.log(`Registered hook: ${hookName}`);
  }

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook to unregister
   */
  unregisterHook(hookName: keyof MenuModuleHooks): void {
    delete this.hooks[hookName];
    this.log(`Unregistered hook: ${hookName}`);
  }

  /**
   * Executes a hook if registered.
   *
   * @param hookName - Name of the hook
   * @param data - Data to pass to the hook
   */
  async executeHook<K extends keyof MenuModuleHooks>(
    hookName: K,
    data: Parameters<NonNullable<MenuModuleHooks[K]>>[0]
  ): Promise<void> {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        await (hook as (data: typeof data) => Promise<void>)(data);
      } catch (error) {
        this.log(
          `Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`
        );
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Event Listeners
  // ---------------------------------------------------------------------------

  /**
   * Sets up event listeners for the menu module.
   */
  private setupEventListeners(): void {
    // Listen for organization deletion to clean up menus
    this.eventService.on('organization.deleted', async (payload) => {
      this.log(`Organization deleted event received: ${payload.organizationId}`);
      // Could trigger menu cleanup for deleted organization
    });

    // Listen for subscription changes that may affect menu limits
    this.eventService.on('subscription.plan.changed', async (payload) => {
      this.log(`Plan changed event received: ${payload.organizationId}`);
      // Could update menu/product limits based on new plan
    });

    // Listen for media deletion that may affect product images
    this.eventService.on('media.deleted', async (payload) => {
      this.log(`Media deleted event received: ${payload.mediaId}`);
      // Could update products that reference this media
    });

    this.log('Event listeners set up');
  }

  // ---------------------------------------------------------------------------
  // Module Settings
  // ---------------------------------------------------------------------------

  /**
   * Gets default module settings.
   *
   * @returns Default menu module settings
   */
  static getDefaultSettings(): MenuModuleSettings {
    return {
      defaultCurrency: 'TRY',
      enableVariants: true,
      enableModifiers: true,
      enableNutritionInfo: false,
      enableAllergens: true,
      maxCategoriesPerMenu: 50,
      maxProductsPerCategory: 100,
      maxVariantsPerProduct: 10,
      maxModifiersPerProduct: 20,
      maxImagesPerProduct: 10,
      imageMaxSizeKb: 2048,
      slugAutoGenerate: true,
    };
  }

  // ---------------------------------------------------------------------------
  // Utility Methods
  // ---------------------------------------------------------------------------

  /**
   * Logs a message with module prefix.
   *
   * @param message - Message to log
   */
  private log(message: string): void {
    // eslint-disable-next-line no-console
    console.log(`[MenuModule] ${message}`);
  }

  /**
   * Checks if module is initialized.
   *
   * @returns True if module is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Gets module metadata.
   *
   * @returns Module metadata object
   */
  static getMetadata() {
    return {
      id: MenuModule.id,
      name: MenuModule.name,
      version: MenuModule.version,
      type: MenuModule.type,
      isCore: MenuModule.isCore,
      routes: MenuModule.routes,
      providers: MenuModule.providers.map((p) => p.name),
      controllers: MenuModule.controllers.map((c) => c.name),
      dependencies: MenuModule.dependencies,
    };
  }
}

// -----------------------------------------------------------------------------
// Module Exports
// -----------------------------------------------------------------------------

/**
 * Default export for module loader dynamic import
 */
export default MenuModule;

/**
 * Export module metadata
 */
export const metadata = MenuModule.getMetadata();
